  ('retired-7ec62a85-moex-00136', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3d2b73b6', 'sub-retired-7ec62a85-02', NULL, 'single_choice', '依司法院大法官解釋意旨，有關徵收補償，下列敘述何者錯誤？', '["徵收之補償應儘速發給，否則徵收土地核准案即應失其效力", "直轄市或縣（市）政府事後發現原發給之補償費短少，得自由裁量是否撤銷原補償處分", "補償應合理、相當", "區段徵收制度中，以徵收後可供建築之抵價地折算抵付補償費，屬徵收補償方式之一種"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
